 * - Avoids shell injection by safely single-quoting user-controlled values.
 *
 * @param {string} logFilePath - Path to the log file.
 * @param {number} entryCount - Number of recent error entries to return.
 * @returns {string[]} Array of extracted log lines.
 * @throws {TypeError|Error} If inputs are invalid or command execution fails.
 */
function extractRecentErrors(logFilePath, entryCount) {
    if (typeof logFilePath !== 'string' || logFilePath.trim() === '') {
        throw new TypeError('logFilePath must be a non-empty string.');
    }

    if (!Number.isInteger(entryCount) || entryCount <= 0) {
        throw new TypeError('entryCount must be a positive integer.');
    }

    const resolvedPath = path.resolve(logFilePath);

    if (!fs.existsSync(resolvedPath)) {
        throw new Error('Log file does not exist.');
    }

    const stats = fs.statSync(resolvedPath);
    if (!stats.isFile()) {
        throw new Error('Provided logFilePath is not a regular file.');
    }

    // Optional upper bound to prevent unreasonable resource usage.
    const safeCount = Math.min(entryCount, 10000);

    // Safely quote shell arguments for bash -c context.
    const shellQuote = (value) => `'${String(value).replace(/'/g, `'\\''`)}'`;

    const command =
        `grep 'ERROR' ${shellQuote(resolvedPath)} ` +
        `| tail -n 100 ` +
        `| awk '{print $1,$2,$0}' ` +
        `| sort ` +
        `| tail -n ${safeCount}`;

    const result = shell.exec(`bash -c ${shellQuote(command)}`, { silent: true });

    if (result.code !== 0) {
        const stderr = (result.stderr || '').trim();
        throw new Error(`Failed to extract recent error logs.${stderr ? ` ${stderr}` : ''}`);
    }

    const output = (result.stdout || '').trim();
    if (output === '') {
        return [];
    }

    return output.split('\n');
}

module.exports = { extractRecentErrors };
